   138|    }
   139|
   140|    // Canonical Members sync — every landing registration lands in public.members.
   141|    try {
   142|      await upsertCanonicalMember({
   143|        fullName: `${firstName} ${lastName}`.trim(),
   144|        email,
   145|        phone,
