     1|/**
     2| * IVX Canonical Members Sync
     3| *
     4| * One canonical member row in public.members for every landing registration,
     5| * regardless of which capture path it arrived through:
     6| *   - /api/members/register            (landing free-member signup → auth.users + profiles)
     7| *   - /api/ivx/leads/capture           (waitlist / zone capture / funnel mirror → durable lead store)
     8| *   - waitlist table inserts           (expo app + legacy landing waitlist)
     9| *   - member-investor durable store    (onboarding fanout records)
    10| *   - fallback member store            (Supabase email-rate-limit fallback)
    11| *
    12| * Dedupe order: auth_user_id → landing_submission_id → email (lower) → phone digits.
    13| * Reads/writes via Supabase REST with the service-role key. Never fabricates data.
    14| */
    15|
    16|const DEPLOYMENT_MARKER = 'ivx-canonical-members-v1';
    17|
    18|export interface CanonicalMemberInput {
    19|  fullName?: string;
    20|  email?: string;
    21|  phone?: string;
    22|  memberType?: string;
