   101|async function rest<T>(pathName: string, init: RequestInit = {}, prefer?: string): Promise<T> {
   102|  const response = await fetch(`${getSupabaseUrl()}/rest/v1${pathName}`, {
   103|    ...init,
   104|    headers: { ...headers(prefer), ...(init.headers ?? {}) },
   105|  });
   106|  const text = await response.text();
   107|  let payload: unknown = null;
   108|  try { payload = text ? JSON.parse(text) : null; } catch { payload = text; }
   109|  if (!response.ok) {
   110|    const message =
   111|      payload && typeof payload === 'object'
   112|        ? String((payload as Record<string, unknown>).message ?? (payload as Record<string, unknown>).error ?? `HTTP ${response.status}`)
   113|        : `HTTP ${response.status}`;
   114|    throw new Error(`Supabase members REST ${response.status}: ${message}`);
   115|  }
   116|  return payload as T;
   117|}
