   131|const VALID_MEMBER_TYPES = new Set([
   132|  'member', 'investor', 'buyer', 'realtor', 'influencer', 'jv_partner',
   133|  'seller', 'builder', 'developer', 'lender', 'land_owner', 'broker', 'owner',
   134|  'jv_deals', 'tokenized',
   135|]);
   136|
   137|function normalizeMemberType(value: unknown): string {
   138|  const raw = typeof value === 'string' ? value.trim().toLowerCase() : '';
   139|  if (VALID_MEMBER_TYPES.has(raw)) return raw === 'broker' ? 'realtor' : raw === 'developer' ? 'builder' : raw;
   140|  return 'member';
