   143|async function findExisting(input: CanonicalMemberInput): Promise<CanonicalMemberRow | null> {
   144|  const authUserId = (input.authUserId || '').trim();
   145|  if (authUserId) {
   146|    const rows = await rest<CanonicalMemberRow[]>(`/members?auth_user_id=eq.${encodeURIComponent(authUserId)}&limit=1`);
   147|    if (rows.length > 0) return rows[0];
   148|  }
   149|  const landingSubmissionId = (input.landingSubmissionId || '').trim();
   150|  if (landingSubmissionId) {
   151|    const rows = await rest<CanonicalMemberRow[]>(`/members?landing_submission_id=eq.${encodeURIComponent(landingSubmissionId)}&limit=1`);
   152|    if (rows.length > 0) return rows[0];
   153|  }
   154|  const email = normEmail(input.email);
   155|  if (email) {
   156|    const rows = await rest<CanonicalMemberRow[]>(`/members?email=ilike.${encodeURIComponent(email)}&limit=1`);
   157|    if (rows.length > 0) return rows[0];
   158|  }
   159|  const phoneDigits = normPhoneDigits(input.phone);
   160|  if (phoneDigits.length >= 10) {
   161|    const rows = await rest<CanonicalMemberRow[]>(`/members?phone=like.*${encodeURIComponent(phoneDigits.slice(-10))}&limit=1`);
   162|    if (rows.length > 0) return rows[0];
   163|  }
   164|  return null;
   165|}
