   167|/**
   168| * Insert or merge one canonical member. Returns the row plus whether it was
   169| * created, updated, or skipped (existing row already had all incoming data).
   170| */
   171|export async function upsertCanonicalMember(
   172|  input: CanonicalMemberInput
   173|): Promise<{ ok: boolean; action: 'created' | 'updated' | 'skipped'; member?: CanonicalMemberRow; error?: string }> {
   174|  if (!isCanonicalMembersConfigured()) {
   175|    return { ok: false, action: 'skipped', error: 'Supabase credentials missing' };
   176|  }
   177|  const email = normEmail(input.email);
   178|  const phone = (input.phone || '').trim();
   179|  if (!email && normPhoneDigits(phone).length < 10 && !(input.authUserId || '').trim()) {
   180|    return { ok: false, action: 'skipped', error: 'No dedupe identity (email/phone/auth user id)' };
   181|  }
   182|
   183|  try {
   184|    const existing = await findExisting(input);
   185|    const createdAt = input.createdAt && !Number.isNaN(new Date(input.createdAt).getTime())
   186|      ? new Date(input.createdAt).toISOString()
   187|      : nowIso();
   188|
   189|    if (!existing) {
   190|      const inserted = await rest<CanonicalMemberRow[]>(
   191|        '/members',
   192|        {
   193|          method: 'POST',
   194|          body: JSON.stringify({
   195|            full_name: (input.fullName || '').trim(),
   196|            email,
   197|            phone,
   198|            member_type: normalizeMemberType(input.memberType),
   199|            source: (input.source || 'landing_page').trim() || 'landing_page',
   200|            source_detail: (input.sourceDetail || '').trim(),
   201|            verification_status: (input.verificationStatus || 'unverified').trim() || 'unverified',
   202|            sms_verified: Boolean(input.smsVerified),
   203|            email_verified: Boolean(input.emailVerified),
   204|            investor_interest: (input.investorInterest || '').trim(),
   205|            preferred_zipcode: (input.preferredZipcode || '').trim(),
   206|            budget_range: (input.budgetRange || '').trim(),
   207|            picture_url: (input.pictureUrl || '').trim(),
   208|            auth_user_id: (input.authUserId || '').trim() || null,
   209|            landing_submission_id: (input.landingSubmissionId || '').trim() || null,
   210|            created_at: createdAt,
   211|            updated_at: nowIso(),
   212|          }),
   213|        },
